const express = require('express');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

const pool = new Pool({
  user: 'postgres', // Superuser account
  host: 'localhost',
  database: 'your_database_name',
  password: 'your_password',
  port: 5432,
});

// Create table
app.post('/create-table', async (req, res) => {
  const { tableName } = req.body;
  try {
    await pool.query(`CREATE TABLE IF NOT EXISTS ${tableName} (id SERIAL PRIMARY KEY, data JSONB)`);
    res.status(201).send(`Table ${tableName} created`);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

// Create record
app.post('/records/:tableName', async (req, res) => {
  const { tableName } = req.params;
  const { data } = req.body;
  try {
    const result = await pool.query(`INSERT INTO ${tableName} (data) VALUES ($1) RETURNING *`, [data]);
    res.status(201).json(result.rows[0]);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

// Read records
app.get('/records/:tableName', async (req, res) => {
  const { tableName } = req.params;
  try {
    const result = await pool.query(`SELECT * FROM ${tableName}`);
    res.status(200).json(result.rows);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

// Update record
app.put('/records/:tableName/:id', async (req, res) => {
  const { tableName, id } = req.params;
  const { data } = req.body;
  try {
    const result = await pool.query(`UPDATE ${tableName} SET data = $1 WHERE id = $2 RETURNING *`, [data, id]);
    res.status(200).json(result.rows[0]);
  } catch (err) {
    res.status(500).send(err.message);
  }
});

// Delete record
app.delete('/records/:tableName/:id', async (req, res) => {
  const { tableName, id } = req.params;
  try {
    await pool.query(`DELETE FROM ${tableName} WHERE id = $1`, [id]);
    res.status(204).send();
  } catch (err) {
    res.status(500).send(err.message);
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});